// AIR processing deferred to Laravel AirFileParser
// N8n sends callback immediately with "pending_air_processing" status
// Laravel will trigger AirFileParser skill when it receives this status

const items = $input.all();
const results = [];

for (const item of items) {
  results.push({
    json: {
      document_id: item.json.document_id,
      document_type: 'air',
      extraction_status: 'deferred',
      extraction_method: 'laravel-airfileparser-fallback',
      message: 'AIR file processing deferred to Laravel AirFileParser (N8n Phase 2 limitation)',
      file_path: item.json.file_path,
      company_id: item.json.company_id,
      supplier_id: item.json.supplier_id,
      callback_url: item.json.callback_url,
      processing_timestamp: new Date().toISOString(),
      deferred_reason: 'AIR format requires Laravel AirFileParser skill - not available in N8n Phase 2'
    }
  });
}

return results;
